import Blockly from 'blockly/core';
import ros2HeadBlocks from './blockJson/ros2_command_ai_HEAD.json';

const MOTION_TASK_OPTIONS = [
  ['0 MOTION_TASK', '0'],
  ['4 LEGACY_MOTION_TASK', '4'],
  ['5 Pause preset path', '5'],
  ['6 Preset path', '6'],
];

const MOTION_COMMAND_OPTIONS = [
  ['0 default start', '0'],
  ['2 when task_type==5', '2'],
  ['4 stop all', '4'],
];

const MOTION_BLOCKING_OPTIONS = [
  ['NONE', 'NONE'],
  ['SOFT', 'SOFT'],
  ['HARD', 'HARD'],
  ['LOOP', 'LOOP'],
  ['WAIT', 'WAIT'],
];

const getMotionCommandOptionsByTaskType = (taskType) => {
  if (taskType === '5') return MOTION_COMMAND_OPTIONS;
  return MOTION_COMMAND_OPTIONS.filter(([, value]) => value !== '2');
};

const createMotionCommandField = () => new Blockly.FieldDropdown(function () {
  const sourceBlock = this.getSourceBlock();
  const taskType = sourceBlock ? sourceBlock.getFieldValue('TASK_TYPE') : '0';
  return getMotionCommandOptionsByTaskType(taskType);
});

const getFirstOptionValue = (options) => (options.length ? options[0][1] : '0');

const hasOptionValue = (options, value) => options.some(([, v]) => v === value);

const updateHeadMotionCommandOptions = (block) => {
  const taskType = block.getFieldValue('TASK_TYPE');
  const commandOptions = getMotionCommandOptionsByTaskType(taskType);
  const commandField = block.getField('COMMAND_TYPE');
  if (!commandField) return;

  const currentCommand = block.getFieldValue('COMMAND_TYPE');
  if (!hasOptionValue(commandOptions, currentCommand)) {
    block.setFieldValue(getFirstOptionValue(commandOptions), 'COMMAND_TYPE');
  }
};

const updateHeadMotionChildParams = (block) => {
  const taskType = block.getFieldValue('TASK_TYPE');
  const showMotionId = taskType === '0' || taskType === '5';
  const showLegacyId = taskType === '4';
  const showPresetId = taskType === '6';

  const motionInput = block.getInput('MOTION_ID_INPUT');
  const legacyInput = block.getInput('LEGACY_ID_INPUT');
  const presetInput = block.getInput('PRESET_ID_INPUT');

  if (motionInput) motionInput.setVisible(showMotionId);
  if (legacyInput) legacyInput.setVisible(showLegacyId);
  if (presetInput) presetInput.setVisible(showPresetId);
};

const syncHeadMotionBlockByOptions = (block) => {
  if (block.motionSyncing) return;
  block.motionSyncing = true;

  updateHeadMotionCommandOptions(block);
  updateHeadMotionChildParams(block);

  if (block.rendered) {
    block.render();
  }

  block.motionSyncing = false;
};

const registerHeadMotionBlock = () => {
  Blockly.Blocks.c_ai_head_motion = {
    init: function () {
      this.appendDummyInput('TASK_TYPE_INPUT')
        .appendField('HEAD motion task_type')
        .appendField(new Blockly.FieldDropdown(MOTION_TASK_OPTIONS), 'TASK_TYPE');

      this.appendDummyInput('COMMAND_BLOCKING_INPUT')
        .appendField('command_type')
        .appendField(createMotionCommandField(), 'COMMAND_TYPE')
        .appendField('blocking_type')
        .appendField(new Blockly.FieldDropdown(MOTION_BLOCKING_OPTIONS), 'BLOCKING_TYPE');

      this.appendDummyInput('MOTION_ID_INPUT')
        .appendField('motion_id')
        .appendField(new Blockly.FieldNumber(1, 0, undefined, 1), 'MOTION_ID');

      this.appendDummyInput('LEGACY_ID_INPUT')
        .appendField('legacy_id')
        .appendField(new Blockly.FieldNumber(0, 0, undefined, 1), 'LEGACY_ID');

      this.appendDummyInput('PRESET_ID_INPUT')
        .appendField('preset_id')
        .appendField(new Blockly.FieldNumber(0, 0, undefined, 1), 'PRESET_ID');

      this.setPreviousStatement(true);
      this.setNextStatement(true);
      this.setStyle('execute_blocks');
      this.setTooltip('VDA_ACTION.MOTION -> /motion_manager/task_cmd (motion_manager_msgs/msg/TaskCmd)');
      this.setHelpUrl('');

      syncHeadMotionBlockByOptions(this);
    },
    onchange: function (event) {
      if (!this.workspace || this.isInFlyout) return;
      if (this.motionSyncing) return;
      if (event && event.blockId && event.blockId !== this.id) return;

      // Keep root/child option dependent parameters in sync.
      syncHeadMotionBlockByOptions(this);
    },
  };
};

const registerBlockFromJson = (blockDef) => {
  Blockly.Blocks[blockDef.type] = {
    init: function () {
      this.jsonInit(blockDef);
    },
  };
};

const registerBlocksFromJson = (blockDefs) => {
  registerHeadMotionBlock();

  blockDefs.forEach((blockDef) => {
    if (!blockDef || !blockDef.type) return;
    if (blockDef.type === 'c_ai_head_motion') return;
    registerBlockFromJson(blockDef);
  });
};

registerBlocksFromJson(ros2HeadBlocks);

export { ros2HeadBlocks };
